WITH anchor AS (
  SELECT LEAST(max(day), ((now() AT TIME ZONE '$timezone')::date - 1)) AS d FROM health.steps_daily
), days AS (
  SELECT generate_series((SELECT d FROM anchor)::timestamp, (SELECT d FROM anchor)::timestamp - INTERVAL '400 days', INTERVAL '-1 day')::date AS day
), ranked AS (
  SELECT d.day, COALESCE(s.steps, 0) >= $steps_goal AS hit, row_number() OVER (ORDER BY d.day DESC) AS rn
  FROM days d LEFT JOIN health.steps_daily s ON s.day = d.day
), first_miss AS (
  SELECT min(rn) AS rn FROM ranked WHERE NOT hit
)
SELECT COALESCE((SELECT rn - 1 FROM first_miss), count(*)) AS current_streak FROM ranked
